python3 -c "
import pysam
import os
# create a tiny test BAM? Instead, let's just test the sort call on our temp.bam if exists.
# But we don't have temp.bam yet. Let's first create a small filtered BAM using pysam.
# We'll do a quick test: filter first few reads.
with pysam.AlignmentFile('input.bam', 'rb') as infile:
    reads = []
    for i, read in enumerate(infile):
        if i >= 2:
            break
        if read.mapping_quality >= 30:
            reads.append(read)
    if len(reads) == 0:
        # just take any two reads
        infile.reset()
        for i, read in enumerate(infile):
            if i >= 2:
                break
            reads.append(read)
    # write to temp.bam
    with pysam.AlignmentFile('test_temp.bam', 'wb', header=infile.header) as outfile:
        for r in reads:
            outfile.write(r)
# now try to sort with pysam.sort using -o and -T
try:
    pysam.sort('-o', 'test_sorted.bam', '-T', 'test_prefix', 'test_temp.bam')
    print('Sort succeeded')
except Exception as e:
    print('Sort failed:', e)
finally:
    if os.path.exists('test_temp.bam'):
        os.remove('test_temp.bam')
    if os.path.exists('test_sorted.bam'):
        os.remove('test_sorted.bam')
    if os.path.exists('test_sorted.bam.bai'):
        os.remove('test_sorted.bam.bai')
"
